/* Lift and Coast — front-end logic. Reads window.LAC_DATA (generated by
   pipeline/export_web.py). No framework, no build step.

   Routes (hash-based):
     #/                 season dossier (default season)
     #/s/<year>         season dossier for <year>   (deep-link target from lists)
     #<year>            legacy alias for #/s/<year>
     #/beaten           cross-season: champions beaten by their teammate
     #/scoring          cross-season: scoring-sensitive titles (flips + ties, distinct)
     #/finals           cross-season: final-race deciders
     #/clinch           cross-season: earliest title clinches
*/
(function () {
  "use strict";
  var DATA = window.LAC_DATA;
  if (!DATA) { document.body.innerHTML = "<p style='padding:40px;font-family:monospace'>data.js failed to load — run <code>python3 pipeline/export_web.py</code>.</p>"; return; }

  var seasons = DATA.seasons;
  var byYear = {};
  seasons.forEach(function (s) { byYear[s.year] = s; });
  var years = seasons.map(function (s) { return s.year; });

  var $ = function (id) { return document.getElementById(id); };
  var el = function (tag, cls, html) {
    var e = document.createElement(tag);
    if (cls) e.className = cls;
    if (html != null) e.innerHTML = html;
    return e;
  };
  var fmt = function (n) {
    return (Math.round(n * 10) / 10).toString().replace(/\.0$/, "");
  };
  var esc = function (s) { return String(s == null ? "" : s).replace(/[&<>]/g, function (c) {
    return { "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]; }); };
  var last = function (name) { return String(name || "").split(" ").slice(-1)[0]; };

  /* ====================================================================== */
  /*  STAT TOWER (shared header)                                            */
  /* ====================================================================== */
  function tower() {
    var t = DATA.meta.totals;
    var cells = [
      [t.seasons, "seasons", null],
      [t.races.toLocaleString(), "grands prix", null],
      [t.drivers, "drivers", null],
      [t.finaleTitles, "to the final race", "#/finals"],
      [t.scoringSensitive, "scoring-sensitive", "#/scoring"],
      [t.tieSeasons, "tie under a system", "#/scoring"],
    ];
    var host = $("tower"); host.innerHTML = "";
    cells.forEach(function (c) {
      var cell = el(c[2] ? "a" : "div", "cell" + (c[2] ? " cell-link" : ""));
      if (c[2]) { cell.href = c[2]; }
      cell.appendChild(el("div", "t-num num", c[0]));
      cell.appendChild(el("div", "t-lab", c[1]));
      host.appendChild(cell);
    });
  }

  /* ====================================================================== */
  /*  SEASON DOSSIER                                                        */
  /* ====================================================================== */
  function flags(s) {
    var host = $("flags"); host.innerHTML = "";
    if (s.clinch.wentToFinale) host.appendChild(el("span", "flag wire", "went to the wire"));
    else if (s.clinch.racesRemaining >= 3) host.appendChild(el("span", "flag domin", "clinched +" + s.clinch.racesRemaining));
    if (s.teammate.outQualified || s.teammate.outRaced) host.appendChild(el("span", "flag anom", "beaten by teammate"));
    if (s.anyChange) host.appendChild(el("span", "flag scoring", "scoring-sensitive"));
  }

  function champion(s) {
    var b = $("champ-body"); b.innerHTML = "";
    b.appendChild(el("div", "champ-name", esc(s.champion)));
    b.appendChild(el("div", "champ-team", esc(s.constructor)));
    var stats = el("div", "champ-stats");
    [[fmt(s.points), "points"], [s.wins, "wins"], [s.clinch.totalRounds, "rounds"]].forEach(function (x) {
      var st = el("div", "stat");
      st.appendChild(el("div", "s-num num", x[0]));
      st.appendChild(el("div", "s-lab", x[1]));
      stats.appendChild(st);
    });
    b.appendChild(stats);
  }

  function clinch(s) {
    var c = s.clinch, b = $("clinch-body"); b.innerHTML = "";
    var line = el("div", "clinch-line");
    line.appendChild(el("span", "clinch-round num", "R" + c.round));
    line.appendChild(el("span", "clinch-race", esc(c.race || "")));
    b.appendChild(line);
    b.appendChild(el("div", "clinch-meta",
      c.wentToFinale
        ? "decided at the final round — mathematically open until the flag"
        : "secured with <b style='color:var(--t-green)'>" + c.racesRemaining + "</b> race" + (c.racesRemaining === 1 ? "" : "s") + " still to run"));
    var bar = el("div", "racebar");
    for (var r = 1; r <= c.totalRounds; r++) {
      var cls = r < c.round ? "rb run" : (r === c.round ? "rb clinch" : "rb after");
      var seg = el("div", cls);
      seg.title = "Round " + r + (r === c.round ? " — clinched" : "");
      bar.appendChild(seg);
    }
    b.appendChild(bar);
    b.appendChild(el("div", "clinch-margin",
      "closest the lead ever got: <b>" + fmt(c.closestMargin) + "</b> pts between P1 and P2"));
  }

  function invariance(s) {
    var b = $("inv-body"); b.innerHTML = "";
    var table = el("table", "inv-table");
    table.innerHTML = "<thead><tr><th>scoring system</th><th>champion</th><th class='inv-pts'>pts</th></tr></thead>";
    var tb = el("tbody");
    s.invariance.forEach(function (i) {
      var tr = el("tr");
      tr.appendChild(el("td", "inv-sys", esc(i.table) + (i.own ? " <span style='color:var(--amber)' title='the era\\'s real table'>&#9666;era</span>" : "")));
      var who = el("td", "inv-who " + (i.tie ? "tie" : (i.changes ? "flip" : "held")));
      if (i.tie) {
        who.innerHTML = esc(i.champ.replace(/^TIE:\s*/, "")) + "<span class='inv-tag tie'>tie</span>";
      } else if (i.changes) {
        who.innerHTML = esc(i.champ) + "<span class='inv-tag flip'>flip</span>";
      } else {
        who.textContent = i.champ;
      }
      tr.appendChild(who);
      tr.appendChild(el("td", "inv-pts num", fmt(i.pts)));
      tb.appendChild(tr);
    });
    table.appendChild(tb); b.appendChild(table);
    var foot = "Real champion under the era's actual rules (table, fastest lap <i>and</i> any dropped-scores rule): <b style='color:var(--t-green)'>" +
      esc(s.champion) + "</b>. Each row above applies one table's position points to the real finishing order, with all results counting and no fastest-lap point. ";
    if (s.flips.length) foot += "Some tables would crown <b style='color:var(--amber)'>" + esc(s.flips.join(", ")) + "</b> outright. ";
    if (s.hasTie) foot += "Some tables tie at the top — shown as a tie; the era's countback tie-break (wins, then places) is noted, not recomputed. ";
    if (!s.flips.length && !s.hasTie) foot += "The title is invariant to the scoring table.";
    b.appendChild(el("div", "inv-foot", foot));
  }

  function h2hBar(meWins, themWins, races) {
    var bar = el("div", "h2h-bar");
    var ties = Math.max(0, races - meWins - themWins);
    function seg(cls, n) {
      if (n <= 0) return;
      var s = el("div", "h2h-seg " + cls, String(n));
      s.style.flex = n + " 0 0"; bar.appendChild(s);
    }
    seg("win", meWins); seg("tie", ties); seg("lose", themWins);
    return bar;
  }

  function teammate(s) {
    var t = s.teammate, b = $("tm-body"); b.innerHTML = "";
    var names = el("div", "h2h-names");
    names.appendChild(el("span", "me", esc(last(s.champion)) + " (champ)"));
    names.appendChild(el("span", "them", esc(t.names || "—")));
    b.appendChild(names);
    var q = el("div", "h2h-row");
    q.appendChild(el("div", "h2h-head", "<span>qualifying h2h</span><span>" +
      (t.qualiAvailable ? t.qWins + "&ndash;" + t.qLosses : "n/a") + "</span>"));
    if (t.qualiAvailable) q.appendChild(h2hBar(t.qWins, t.qLosses, t.qRaces));
    else q.appendChild(el("div", "tm-note", "no qualifying-time data before 1994 — race h2h only"));
    b.appendChild(q);
    var r = el("div", "h2h-row");
    r.appendChild(el("div", "h2h-head", "<span>race h2h <span style='color:var(--ink-dim)'>(both classified)</span></span><span>" +
      t.rWins + "&ndash;" + t.rLosses + "</span>"));
    r.appendChild(h2hBar(t.rWins, t.rLosses, t.rRaces));
    b.appendChild(r);
    b.appendChild(el("div", "tm-points",
      "head-to-head points &nbsp; <b>" + fmt(t.champPoints) + "</b> <span style='color:var(--ink-dim)'>champ</span> &nbsp;vs&nbsp; <b>" + fmt(t.tmPoints) + "</b> <span style='color:var(--ink-dim)'>teammate</span>"));
    if (t.outQualified || t.outRaced) {
      var what = [];
      if (t.outQualified) what.push("out-qualified " + t.qLosses + "&ndash;" + t.qWins);
      if (t.outRaced) what.push("out-raced " + t.rLosses + "&ndash;" + t.rWins);
      b.appendChild(el("div", "anomaly", "&#9650; ANOMALY — champion " + what.join(" and ") + " by their own teammate"));
    }
  }

  function renderSeason(year) {
    var s = byYear[year] || byYear[2008];
    $("season").value = s.year;
    $("ro-gap").textContent = "Δ " + fmt(s.clinch.closestMargin) + " pts";
    flags(s); champion(s); clinch(s); invariance(s); teammate(s);
  }

  /* ====================================================================== */
  /*  CROSS-SEASON LIST VIEWS                                               */
  /* ====================================================================== */
  // a head-to-head score like "12–8" with winner side coloured (purple) / loser (yellow)
  function score(aWins, bWins, swap) {
    var aCls = aWins > bWins ? "sc-win" : (aWins < bWins ? "sc-lose" : "sc-tie");
    var bCls = bWins > aWins ? "sc-win" : (bWins < aWins ? "sc-lose" : "sc-tie");
    return "<span class='sc'><span class='" + aCls + "'>" + aWins + "</span>" +
           "<span class='sc-dash'>&ndash;</span><span class='" + bCls + "'>" + bWins + "</span></span>";
  }
  function rowLink(tr, year) {
    tr.className = (tr.className + " lt-row").trim();
    tr.tabIndex = 0;
    tr.setAttribute("role", "link");
    tr.title = "open " + year + " dossier";
    var go = function () { location.hash = "#/s/" + year; };
    tr.addEventListener("click", go);
    tr.addEventListener("keydown", function (e) { if (e.key === "Enter") go(); });
    return tr;
  }
  function ltable(cols) {
    var t = el("table", "lt");
    var thead = "<thead><tr>";
    cols.forEach(function (c) { thead += "<th class='" + (c.cls || "") + "'>" + c.h + "</th>"; });
    t.innerHTML = thead + "</tr></thead>";
    t.appendChild(el("tbody"));
    return t;
  }
  function yearCell(y) { return "<td class='lt-year num'>" + y + "</td>"; }

  // 1) champions beaten by their teammate ---------------------------------
  function renderBeaten() {
    var rows = seasons.filter(function (s) { return s.teammate.outQualified || s.teammate.outRaced; });
    rows.sort(function (a, b) {
      var sev = function (s) {
        return (s.teammate.outQualified ? s.teammate.qLosses - s.teammate.qWins : 0) +
               (s.teammate.outRaced ? s.teammate.rLosses - s.teammate.rWins : 0);
      };
      return sev(b) - sev(a) || b.year - a.year;
    });
    var host = el("div");
    var t = ltable([
      { h: "season", cls: "lt-year" }, { h: "champion" }, { h: "teammate" },
      { h: "quali h2h", cls: "lt-r" }, { h: "race h2h", cls: "lt-r" }, { h: "", cls: "lt-tag" },
    ]);
    var tb = t.querySelector("tbody");
    rows.forEach(function (s) {
      var tm = s.teammate;
      var tag = (tm.outQualified && tm.outRaced) ? "both" : (tm.outQualified ? "out-qualified" : "out-raced");
      var quali = tm.qualiAvailable
        ? score(tm.qWins, tm.qLosses)
        : "<span class='lt-na'>&mdash; <span class='lt-na-sub'>race only</span></span>";
      var tr = el("tr");
      tr.innerHTML = yearCell(s.year) +
        "<td class='lt-name'>" + esc(s.champion) + "</td>" +
        "<td class='lt-name lt-them'>" + esc(tm.names || "—") + "</td>" +
        "<td class='lt-r'>" + quali + "</td>" +
        "<td class='lt-r'>" + score(tm.rWins, tm.rLosses) + "</td>" +
        "<td class='lt-tag'><span class='tg tg-anom'>" + tag + "</span></td>";
      tb.appendChild(rowLink(tr, s.year));
    });
    host.appendChild(t);
    host.appendChild(el("p", "lt-note",
      "The drivers' champion was out-paced by their own teammate over the season — qualifying head-to-head and/or race head-to-head (both classified). Same car, so this is the cleanest measure of being beaten by the man in the other garage. Qualifying head-to-head needs 1994+ timing data; earlier rows are race-only. Figures are Phase A's teammate spine joined to each champion."));
    return host;
  }

  // 2) scoring-sensitive titles (flips + ties, kept distinct) --------------
  function systemsWhere(s, pred) {
    return s.invariance.filter(pred).map(function (i) { return i.table; });
  }
  function tiePartners(s, champ) {
    var names = {};
    s.invariance.filter(function (i) { return i.tie; }).forEach(function (i) {
      i.champ.replace(/^TIE:\s*/, "").split(" / ").forEach(function (n) {
        if (n.trim() && n.trim() !== champ) names[n.trim()] = 1;
      });
    });
    return Object.keys(names);
  }
  function scoringBlock(title, sub, rows, kind) {
    var wrap = el("div", "lt-block");
    wrap.appendChild(el("h2", "lt-block-h",
      esc(title) + " <span class='lt-count'>" + rows.length + "</span>"));
    wrap.appendChild(el("p", "lt-block-sub", sub));
    var t = ltable([
      { h: "season", cls: "lt-year" }, { h: "real champion" },
      { h: kind === "flip" ? "would instead win" : "ties at the top with" },
      { h: "under", cls: "lt-sys" },
    ]);
    var tb = t.querySelector("tbody");
    rows.forEach(function (s) {
      var showcase = (s.year === 1988 || s.year === 2008);
      var alts, sys;
      if (kind === "flip") {
        alts = s.flips.join(", ");
        sys = systemsWhere(s, function (i) { return i.changes; });
      } else {
        alts = tiePartners(s, s.champion).join(", ");
        sys = systemsWhere(s, function (i) { return i.tie; });
      }
      var uniqSys = sys.filter(function (v, i) { return sys.indexOf(v) === i; });
      var tr = el("tr" );
      if (showcase) tr.className = "lt-showcase";
      tr.innerHTML = yearCell(s.year) +
        "<td class='lt-name'>" + esc(s.champion) + (showcase ? " <span class='tg tg-star'>showcase</span>" : "") + "</td>" +
        "<td class='lt-name " + (kind === "flip" ? "lt-flip" : "lt-tiealt") + "'>" + esc(alts) + "</td>" +
        "<td class='lt-sys'>" + uniqSys.map(function (x) { return "<span class='chip'>" + esc(x) + "</span>"; }).join("") + "</td>";
      tb.appendChild(rowLink(tr, s.year));
    });
    wrap.appendChild(t);
    return wrap;
  }
  function renderScoring() {
    var host = el("div");
    var flips = seasons.filter(function (s) { return s.anyChange; }).sort(function (a, b) { return a.year - b.year; });
    var ties = seasons.filter(function (s) { return s.hasTie; }).sort(function (a, b) { return a.year - b.year; });
    host.appendChild(scoringBlock(
      "Title would flip", "A different driver wins outright under another historical points table (position points only, all results counting, no fastest-lap point). 1988 is the dropped-scores story — under all-results scoring Prost beats Senna.",
      flips, "flip"));
    host.appendChild(scoringBlock(
      "Tie at the top", "Under another table the championship is level at the top — reported as a genuine tie, NOT a flip. The era's countback tie-break (wins, then places) is noted, not recomputed.",
      ties, "tie"));
    host.appendChild(el("p", "lt-note",
      "Flips (" + flips.length + ") and ties (" + ties.length + ") are kept strictly distinct. A season can appear in both lists when different tables produce different outcomes (e.g. 2008 flips to Massa under the 6-pt-gap systems but ties under the top-5 8-6-4-3-2)."));
    return host;
  }

  // 3) final-race deciders -------------------------------------------------
  function renderFinals() {
    var rows = seasons.filter(function (s) { return s.clinch.wentToFinale; })
      .sort(function (a, b) { return a.clinch.closestMargin - b.clinch.closestMargin || b.year - a.year; });
    var host = el("div");
    var t = ltable([
      { h: "season", cls: "lt-year" }, { h: "deciding race" },
      { h: "champion" }, { h: "runner-up" }, { h: "closest margin", cls: "lt-r" },
    ]);
    var tb = t.querySelector("tbody");
    rows.forEach(function (s) {
      var m = s.clinch.closestMargin;
      var tr = el("tr");
      tr.innerHTML = yearCell(s.year) +
        "<td class='lt-name'>" + esc(s.clinch.race) + "</td>" +
        "<td class='lt-name'>" + esc(s.champion) + "</td>" +
        "<td class='lt-name lt-them'>" + esc(s.runnerUp || "—") + "</td>" +
        "<td class='lt-r'><span class='" + (m <= 1 ? "mg-tight" : "mg") + " num'>" + fmt(m) + "</span></td>";
      tb.appendChild(rowLink(tr, s.year));
    });
    host.appendChild(t);
    host.appendChild(el("p", "lt-note",
      "Every season whose title was mathematically open going into the final round (" + rows.length + " of " + DATA.meta.totals.seasons + "). Sorted by the closest the lead ever got between P1 and P2 across the season (running standings) — lowest first. Margin is in championship points of the era."));
    return host;
  }

  // 4) earliest clinches ---------------------------------------------------
  function renderClinch() {
    var rows = seasons.slice().sort(function (a, b) {
      return b.clinch.racesRemaining - a.clinch.racesRemaining || a.year - b.year;
    });
    var host = el("div");
    var t = ltable([
      { h: "season", cls: "lt-year" }, { h: "champion" },
      { h: "clinched at" }, { h: "races to spare", cls: "lt-r" },
    ]);
    var tb = t.querySelector("tbody");
    rows.forEach(function (s) {
      var rr = s.clinch.racesRemaining;
      var tr = el("tr");
      tr.innerHTML = yearCell(s.year) +
        "<td class='lt-name'>" + esc(s.champion) + "</td>" +
        "<td class='lt-name lt-them'>R" + s.clinch.round + " &middot; " + esc(s.clinch.race) + "</td>" +
        "<td class='lt-r'><span class='" + (rr >= 3 ? "sp-big" : "sp") + " num'>" + rr + "</span></td>";
      tb.appendChild(rowLink(tr, s.year));
    });
    host.appendChild(t);
    host.appendChild(el("p", "lt-note",
      "Most dominant seasons by how early the title was mathematically secured — the counterpoint to the final-race deciders (which sit at 0). Clinch uses the era's real points system and remaining-points math; it is sound (never early), and can read one race conservative pre-1991 due to dropped scores."));
    return host;
  }

  var VIEWS = {
    "#/beaten":  { tab: "#/beaten",  title: "Champions beaten by their teammate",
                   sub: "The 2016 Rosberg anomaly, generalised across 75 seasons.", render: renderBeaten },
    "#/scoring": { tab: "#/scoring", title: "Scoring-sensitive titles",
                   sub: "Where the points system, not the driving, decides the champion.", render: renderScoring },
    "#/finals":  { tab: "#/finals",  title: "Final-race deciders",
                   sub: "Titles still mathematically open at the last round.", render: renderFinals },
    "#/clinch":  { tab: "#/clinch",  title: "Earliest clinches",
                   sub: "Titles secured with the most races to spare.", render: renderClinch },
  };

  /* ====================================================================== */
  /*  ROUTER                                                                */
  /* ====================================================================== */
  function setActiveTab(route) {
    var tabs = document.querySelectorAll("#tabs .tab");
    for (var i = 0; i < tabs.length; i++) {
      tabs[i].classList.toggle("active", tabs[i].getAttribute("data-route") === route);
    }
  }
  function showSeasonView(show) {
    $("view-season").hidden = !show;
    $("view-list").hidden = show;
  }

  function route() {
    var h = location.hash || "#/";
    // legacy bare-year hash (e.g. #2008)
    var bare = h.match(/^#(\d{4})$/);
    if (bare) { location.replace("#/s/" + bare[1]); return; }

    var sm = h.match(/^#\/s\/(\d{4})$/);
    if (VIEWS[h]) {
      var v = VIEWS[h];
      showSeasonView(false);
      setActiveTab(v.tab);
      $("list-title").textContent = v.title;
      $("list-sub").textContent = v.sub;
      var body = $("list-body"); body.innerHTML = "";
      body.appendChild(v.render());
      $("ro-gap").textContent = h.replace("#/", "").toUpperCase();
      window.scrollTo(0, 0);
    } else {
      var yr = sm ? +sm[1] : (byYear[+(h.replace(/[^\d]/g, ""))] ? +(h.replace(/[^\d]/g, "")) : 2008);
      showSeasonView(true);
      setActiveTab("#/");
      renderSeason(yr);
      if (sm) window.scrollTo(0, 0);
    }
  }

  /* ====================================================================== */
  /*  INIT                                                                  */
  /* ====================================================================== */
  function init() {
    tower();
    var sel = $("season");
    years.slice().reverse().forEach(function (y) {
      sel.appendChild(el("option", null, y)).value = y;
    });
    sel.addEventListener("change", function () { location.hash = "#/s/" + sel.value; });
    $("prev").addEventListener("click", function () {
      var i = years.indexOf(+sel.value); if (i > 0) location.hash = "#/s/" + years[i - 1];
    });
    $("next").addEventListener("click", function () {
      var i = years.indexOf(+sel.value); if (i < years.length - 1) location.hash = "#/s/" + years[i + 1];
    });
    document.addEventListener("keydown", function (e) {
      if ($("view-season").hidden) return;             // arrows only drive the dossier
      if (e.key === "ArrowLeft") $("prev").click();
      if (e.key === "ArrowRight") $("next").click();
    });
    window.addEventListener("hashchange", route);
    route();
  }

  init();
})();
